function normalizePlatform(p) {
  const v = String(p || '').toLowerCase().trim();
  if (v === 'web') return 'website';
  return v || 'website';
}

const BLOCKED_DOMAINS = [
  'eventim.',
  'ticketmaster.',
  'getgo.',
  'reservix.',
  'adticket.',
  'tickets.',
  'koelnticket.',
  'eventfrog.',
  'rausgegangen.'
];

const DETAIL_PATH_HINTS = [
  '/event/',
  '/veranstaltung/',
  '/etkinlik/',
  '/programm/',
  '/program/'
];

const LISTING_PATH_HINTS = [
  '/calendar',
  '/kalender',
  '/events',
  '/veranstaltungen',
  '/termine',
  '/program',
  '/programm',
  '/tag/',
  '/category/',
  '/kategorie/'
];

function normalizeUrl(rawUrl) {
  let u = String(rawUrl || '').trim();
  if (!u) return null;

  if (!/^https?:\/\//i.test(u)) {
    u = 'https://' + u;
  }

  try {
    const parsed = new URL(u);
    parsed.hash = '';
    const host = parsed.hostname.replace(/^www\./i, '');
    const path = parsed.pathname || '/';
    return `${parsed.protocol}//${host}${path}`;
  } catch {
    return u;
  }
}

function getUrlMeta(rawUrl) {
  try {
    const parsed = new URL(rawUrl);
    const host = parsed.hostname.replace(/^www\./i, '').toLowerCase();
    const path = (parsed.pathname || '/').toLowerCase();
    const segments = path.split('/').filter(Boolean);
    const blockedDomain = BLOCKED_DOMAINS.some(domain => host.includes(domain));
    const isHome = path === '/' || path === '';
    const detailish = DETAIL_PATH_HINTS.some(hint => path.includes(hint)) || segments.some(segment => segment.length >= 24 && segment.includes('-'));
    const listingish = LISTING_PATH_HINTS.some(hint => path === hint || path.startsWith(`${hint}/`) || path.includes(`${hint}?`) || path.includes(hint));

    return {
      host,
      path,
      blockedDomain,
      isHome,
      detailish,
      listingish,
    };
  } catch {
    return {
      host: null,
      path: null,
      blockedDomain: false,
      isHome: false,
      detailish: false,
      listingish: false,
    };
  }
}

const originalUrl = $json.url || null;
const normalizedUrl = normalizeUrl(originalUrl);
const urlMeta = normalizedUrl ? getUrlMeta(normalizedUrl) : getUrlMeta('');

return {
  json: {
    ...$json,
    platform: normalizePlatform($json.platform),
    original_url: originalUrl,
    fetch_url: normalizedUrl,
    url: normalizedUrl,
    source_host: urlMeta.host,
    source_path: urlMeta.path,
    blocked_domain: urlMeta.blockedDomain,
    path_is_home: urlMeta.isHome,
    path_is_detailish: urlMeta.detailish,
    path_is_listingish: urlMeta.listingish,
  }
};

function stripHtml(html) {
  return String(html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--.*?-->/gs, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function getTitle(html) {
  const m = String(html || '').match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return m ? m[1].replace(/\s+/g, ' ').trim() : null;
}

function getMetaContent(html, pattern) {
  const m = String(html || '').match(pattern);
  return m ? String(m[1] || '').trim() : null;
}

function hasJsonLdEvent(html) {
  return /"@type"\s*:\s*"Event"|"@type"\s*:\s*\[\s*"Event"/i.test(String(html || ''));
}

function hasOgEvent(html) {
  return /<meta[^>]+property=["']og:type["'][^>]+content=["']event["']/i.test(String(html || ''));
}

function detectLanguage(text) {
  const t = (text || '').toLowerCase();
  if (/[çğıöşü]/.test(t) || / turkce | türkçe | etkinlik | konser | bilet | dernek | vakif | cami /.test(` ${t} `)) {
    return 'tr';
  }
  return 'de';
}

function guessEntity(text) {
  const t = (text || '').toLowerCase();
  if (/event|veranstaltung|konzert|festival|party|tickets|bilet|etkinlik|gece|iftar|meeting|meetup/.test(t)) {
    return 'EVENT';
  }
  return 'UNKNOWN';
}

function looksGenericTitle(title) {
  const t = String(title || '').toLowerCase().trim();
  if (!t) return true;
  return (
    /^home /.test(t) ||
    /^events? $/.test(t) ||
    /^veranstaltungen $/.test(t) ||
    /^termine $/.test(t) ||
    /^calendar /.test(t) ||
    /^programm $/.test(t) ||
    /^program $/.test(t) ||
    /^tickets? /.test(t) ||
    /^discover /.test(t)
  );
}

function hasDateSignal(text) {
  const t = String(text || '');
  return (
    / \d{1,2}[./-]\d{1,2}([./-]\d{4})? /.test(t) ||
    / \d{4}-\d{2}-\d{2} /.test(t) ||
    / (januar|februar|märz|maerz|april|mai|juni|juli|august|september|oktober|november|dezember|january|february|march|april|may|june|july|august|september|october|november|december) /i.test(t)
  );
}

function hasVenueSignal(text) {
  return /halle|saal|zentrum|center|kultur|moschee|cami|hotel|arena|theater|cafe|restaurant|gemeinde|haus|salon|stage|club|venue|ort |location /i.test(String(text || ''));
}

function hasCommunitySignal(text) {
  return /turk|türk|anatol|iftar|ramadan|ramazan|dernek|vakif|vakf|cami|moschee|konzert|etkinlik|buluşma|bulusma|community|kultur/i.test(String(text || '').toLowerCase());
}

const item = $json;
const statusCode = Number(item.statusCode || 0);

let html = '';
if (typeof item.body === 'string') {
  html = item.body;
} else if (typeof item.data === 'string') {
  html = item.data;
} else if (item.data && typeof item.data.body === 'string') {
  html = item.data.body;
}

let errorMessage = null;

const rawError = item.error ? String(item.error.message || item.error || '') : '';
const combinedError = `${rawError} ${html}`;

if (item.blocked_domain) {
  errorMessage = 'BLOCKED_DOMAIN';
} else if (/ENOTFOUND/i.test(rawError)) {
  errorMessage = 'DNS_NOT_FOUND';
} else if (/EPROTO|SSL/i.test(rawError)) {
  errorMessage = 'SSL_HANDSHAKE_FAILED';
} else if (/timeout/i.test(rawError)) {
  errorMessage = 'TIMEOUT';
} else if (statusCode >= 400) {
  errorMessage = `HTTP_${statusCode}`;
} else if (!html || html.length < 50) {
  errorMessage = 'EMPTY_OR_TOO_SHORT_RESPONSE';
} else if (/captcha|access denied|forbidden|please enable cookies|temporarily unavailable|login|anmelden|einloggen/i.test(combinedError)) {
  errorMessage = 'BLOCKED_OR_LOGIN_WALL';
}

const rawTitle = getTitle(html) || item.name || item.fetch_url || item.url || 'Unknown Source';
const rawText = stripHtml(html).slice(0, 12000);
const normalizedSourceUrl = item.fetch_url || item.url || null;

const jsonLdEvent = hasJsonLdEvent(html);
const ogEvent = hasOgEvent(html);
const dateSignal = hasDateSignal(`${rawTitle} ${rawText}`);
const venueSignal = hasVenueSignal(rawText);
const communitySignal = hasCommunitySignal(`${rawTitle} ${rawText}`);
const citySignal = / berlin | koeln | koln | cologne /i.test(`${rawTitle} ${rawText} ${normalizedSourceUrl || ''}`);
const usefulSignalCount = [jsonLdEvent, ogEvent, dateSignal, venueSignal, communitySignal, citySignal].filter(Boolean).length;
const tooLittleText = rawText.length < 350;
const genericTitle = looksGenericTitle(rawTitle);
const weakListingPage = Boolean(item.path_is_listingish) && !item.path_is_detailish && usefulSignalCount < 2;
const weakHomePage = Boolean(item.path_is_home) && usefulSignalCount < 2;
const weakContent = tooLittleText && usefulSignalCount < 2;

if (!errorMessage && genericTitle && usefulSignalCount < 2) {
  errorMessage = 'GENERIC_TITLE';
} else if (!errorMessage && weakListingPage) {
  errorMessage = 'LISTING_PAGE';
} else if (!errorMessage && weakHomePage) {
  errorMessage = 'HOME_PAGE';
} else if (!errorMessage && weakContent) {
  errorMessage = 'WEAK_CONTENT';
}

const status = errorMessage ? 'ERROR' : 'PENDING';

const payload = {
  source: {
    id: item.id,
    platform: item.platform,
    source_kind: item.source_kind,
    name: item.name,
    url: item.url,
    original_url: item.original_url || null,
    fetch_url: item.fetch_url || item.url || null,
    account_handle: item.account_handle,
    external_id: item.external_id,
    trust_score: item.trust_score,
    host: item.source_host || null,
    path: item.source_path || null,
  },
  fetch_meta: {
    statusCode: statusCode || null,
    headers: item.headers || null,
    error: rawError || null
  },
  fetched_at: new Date().toISOString(),
  title: rawTitle,
  text_excerpt_length: rawText.length,
  quality_signals: {
    jsonLdEvent,
    ogEvent,
    dateSignal,
    venueSignal,
    communitySignal,
    citySignal,
    usefulSignalCount,
    pathIsDetailish: Boolean(item.path_is_detailish),
    pathIsListingish: Boolean(item.path_is_listingish),
    pathIsHome: Boolean(item.path_is_home),
  }
};

return {
  json: {
    source_id: item.id || null,
    platform: item.platform || 'website',
    source_url: normalizedSourceUrl,
    external_id: item.external_id || null,
    raw_title: rawTitle,
    raw_text: rawText || null,
    raw_datetime_text: null,
    raw_location_text: null,
    raw_image_url: null,
    raw_payload_json: JSON.stringify(payload),
    language_hint: detectLanguage(`${rawTitle} ${rawText}`),
    city_guess: null,
    country_code: 'DE',
    entity_guess: guessEntity(`${rawTitle} ${rawText}`),
    status,
    error_message: errorMessage
  }
};

const items = $input.all();

const BLOCKED_DOMAINS = [
  'eventim.',
  'ticketmaster.',
  'getgo.',
  'reservix.',
  'adticket.',
  'tickets.',
  'koelnticket.',
  'eventfrog.',
  'rausgegangen.'
];

const DETAIL_PATH_HINTS = [
  '/event/',
  '/veranstaltung/',
  '/etkinlik/',
  '/programm/',
  '/program/'
];

const EXCLUDED_PATH_HINTS = [
  '/about',
  '/kontakt',
  '/contact',
  '/impressum',
  '/datenschutz',
  '/privacy',
  '/tag/',
  '/category/',
  '/kategorie/',
  '/archive',
  '/archiv',
  '/page/',
  '/author/'
];

const LISTING_HINTS = [
  '/calendar',
  '/kalender',
  '/events',
  '/veranstaltungen',
  '/termine',
  '/program',
  '/programm'
];

function normalizeUrl(rawUrl, baseUrl) {
  if (!rawUrl) return null;

  const value = String(rawUrl).trim();
  if (!value || value.startsWith('#') || /^mailto:|^tel:|^javascript:/i.test(value)) {
    return null;
  }

  try {
    const url = baseUrl ? new URL(value, baseUrl) : new URL(value);
    url.hash = '';
    return url.toString();
  } catch {
    return null;
  }
}

function getHost(url) {
  try {
    return new URL(url).hostname.replace(/^www\./i, '').toLowerCase();
  } catch {
    return null;
  }
}

function getPath(url) {
  try {
    return (new URL(url).pathname || '/').toLowerCase();
  } catch {
    return '/';
  }
}

function isBlockedDomain(host) {
  return host ? BLOCKED_DOMAINS.some(domain => host.includes(domain)) : false;
}

function looksLikeDetailPath(path) {
  const segments = path.split('/').filter(Boolean);
  return (
    DETAIL_PATH_HINTS.some(hint => path.includes(hint)) ||
    segments.some(segment => segment.length >= 24 && segment.includes('-'))
  );
}

function looksExcludedPath(path) {
  if (path === '/' || path === '') return true;
  if (EXCLUDED_PATH_HINTS.some(hint => path.includes(hint))) return true;
  if (/\/(feed|rss)(\/|$)/.test(path)) return true;
  if (/\/(page|seite)\/\d+(\/|$)/.test(path)) return true;
  return false;
}

function looksListingPath(path) {
  return LISTING_HINTS.some(hint => path === hint || path.startsWith(`${hint}/`) || path.includes(hint));
}

function hasAnchorDateSignal(text) {
  const value = String(text || '');
  return (
    /\b\d{1,2}[./-]\d{1,2}([./-]\d{2,4})?\b/.test(value) ||
    /\b\d{1,2}\.\s*(januar|februar|märz|maerz|april|mai|juni|juli|august|september|oktober|november|dezember)\s+\d{4}\b/i.test(value)
  );
}

function looksListingAnchorText(text) {
  return /(tickets|termine|veranstaltungen|events|activities|kalender|calendar|programm|program)\b/i.test(String(text || ''));
}

function hasSingularEventAnchorText(text) {
  const value = String(text || '').toLowerCase();
  if (!value || looksListingAnchorText(value)) return false;

  return /(konzert|festival|iftar|gala|abend|konseri|veranstaltung|etkinlik|workshop|lesung|treffen|buluşma|bulusma)\b/.test(value);
}

function scoreCandidate(url, anchorText) {
  const path = getPath(url);
  const text = String(anchorText || '').toLowerCase();
  let score = 0;

  if (DETAIL_PATH_HINTS.some(hint => path.includes(hint))) score += 5;
  if (looksLikeDetailPath(path)) score += 4;
  if (/event|veranstaltung|etkinlik|konzert|festival|iftar|programm|program/.test(`${path} ${text}`)) score += 3;
  if (/\d{4}|\d{2}-\d{2}|\d{1,2}[.-]\d{1,2}/.test(path)) score += 2;
  if (hasAnchorDateSignal(anchorText)) score += 4;
  if (hasSingularEventAnchorText(anchorText)) score += 3;
  if (hasAnchorDateSignal(anchorText) && hasSingularEventAnchorText(anchorText)) score += 2;
  if (looksListingAnchorText(anchorText)) score -= 4;
  if (looksListingPath(path)) score -= 4;
  if (looksExcludedPath(path)) score -= 8;

  return score;
}

function extractAnchors(html) {
  const results = [];
  const regex = /<a\b[^>]*href\s*=\s*(["'])(.*?)\1[^>]*>([\s\S]*?)<\/a>/gi;
  let match;
  while ((match = regex.exec(String(html || ''))) !== null) {
    const href = match[2];
    const text = String(match[3] || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    results.push({ href, text });
  }
  return results;
}

const output = [];

for (const item of items) {
  const data = item.json || {};
  const baseUrl = data.fetch_url || data.url || null;
  const html = typeof data.body === 'string'
    ? data.body
    : typeof data.data === 'string'
      ? data.data
      : data.data && typeof data.data.body === 'string'
        ? data.data.body
        : '';

  const baseHost = getHost(baseUrl || '');
  const seen = new Set();
  const candidates = [];

  if (baseUrl && data.path_is_detailish && !data.path_is_home && !data.blocked_domain) {
    candidates.push({ url: baseUrl, anchorText: data.name || data.raw_title || '' });
  }

  for (const anchor of extractAnchors(html)) {
    const normalized = normalizeUrl(anchor.href, baseUrl || undefined);
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);

    const host = getHost(normalized);
    if (!host || host !== baseHost) continue;
    if (isBlockedDomain(host)) continue;

    const path = getPath(normalized);
    if (looksExcludedPath(path)) continue;

    const score = scoreCandidate(normalized, anchor.text);
    const detailish = looksLikeDetailPath(path);
    const listingish = looksListingPath(path);

    if (!detailish && score < 4) continue;
    if (listingish && score < 6) continue;

    candidates.push({ url: normalized, anchorText: anchor.text, score });
  }

  const bestCandidates = candidates
    .map(candidate => ({ ...candidate, score: candidate.score ?? scoreCandidate(candidate.url, candidate.anchorText) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 12);

  for (const candidate of bestCandidates) {
    output.push({
      json: {
        ...data,
        original_fetch_url: baseUrl,
        fetch_url: candidate.url,
        source_url: candidate.url,
        candidate_anchor_text: candidate.anchorText || null,
        candidate_score: candidate.score,
      }
    });
  }
}

return output;
